import json
import pymysql
import os
import re
from typing import Dict, Any, List, Optional

# Database connection parameters from environment variables
DB_HOST = os.environ.get('DB_HOST')
DB_USER = os.environ.get('DB_USER')
DB_PASSWORD = os.environ.get('DB_PASSWORD')
DB_NAME = os.environ.get('DB_NAME')
DB_PORT = int(os.environ.get('DB_PORT', 3306))

# Allowlist for searchable columns
ALLOWED_SEARCH_FIELDS = {
    'name', 'category', 'brand', 'sku', 'description'
}

# Allowlist for sortable columns
ALLOWED_SORT_FIELDS = {
    'name', 'price', 'created_at', 'updated_at', 'category', 'brand'
}

# Allowlist for sort directions
ALLOWED_SORT_DIRECTIONS = {'ASC', 'DESC'}

# Maximum results per page
MAX_LIMIT = 100
DEFAULT_LIMIT = 20


def validate_string_input(value: str, max_length: int = 255) -> Optional[str]:
    """Validate and sanitize string input"""
    if not value or not isinstance(value, str):
        return None
    
    value = value.strip()
    
    if len(value) > max_length:
        return None
    
    # Remove any null bytes or control characters
    value = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', value)
    
    return value if value else None


def validate_numeric_input(value: Any, min_val: float = None, max_val: float = None) -> Optional[float]:
    """Validate numeric input"""
    try:
        num_value = float(value)
        
        if min_val is not None and num_value < min_val:
            return None
        
        if max_val is not None and num_value > max_val:
            return None
        
        return num_value
    except (ValueError, TypeError):
        return None


def validate_integer_input(value: Any, min_val: int = None, max_val: int = None) -> Optional[int]:
    """Validate integer input"""
    try:
        int_value = int(value)
        
        if min_val is not None and int_value < min_val:
            return None
        
        if max_val is not None and int_value > max_val:
            return None
        
        return int_value
    except (ValueError, TypeError):
        return None


def get_db_connection():
    """Create a secure database connection"""
    return pymysql.connect(
        host=DB_HOST,
        user=DB_USER,
        password=DB_PASSWORD,
        database=DB_NAME,
        port=DB_PORT,
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5,
        read_timeout=10,
        write_timeout=10
    )


def build_search_query(params: Dict[str, Any]) -> tuple:
    """Build SQL query with parameterized statements"""
    base_query = "SELECT id, name, description, category, brand, sku, price, stock_quantity, created_at, updated_at FROM products"
    
    where_clauses = []
    query_params = []
    
    # Search by keyword across multiple fields
    keyword = validate_string_input(params.get('keyword', ''))
    if keyword:
        search_fields = []
        for field in ['name', 'description', 'brand', 'category']:
            search_fields.append(f"{field} LIKE %s")
            query_params.append(f"%{keyword}%")
        
        where_clauses.append(f"({' OR '.join(search_fields)})")
    
    # Search by specific field
    search_field = params.get('search_field', '')
    search_value = validate_string_input(params.get('search_value', ''))
    
    if search_field in ALLOWED_SEARCH_FIELDS and search_value:
        where_clauses.append(f"{search_field} LIKE %s")
        query_params.append(f"%{search_value}%")
    
    # Filter by category (exact match)
    category = validate_string_input(params.get('category', ''))
    if category:
        where_clauses.append("category = %s")
        query_params.append(category)
    
    # Filter by brand (exact match)
    brand = validate_string_input(params.get('brand', ''))
    if brand:
        where_clauses.append("brand = %s")
        query_params.append(brand)
    
    # Filter by price range
    min_price = validate_numeric_input(params.get('min_price'), min_val=0)
    if min_price is not None:
        where_clauses.append("price >= %s")
        query_params.append(min_price)
    
    max_price = validate_numeric_input(params.get('max_price'), min_val=0)
    if max_price is not None:
        where_clauses.append("price <= %s")
        query_params.append(max_price)
    
    # Filter by stock availability
    in_stock = params.get('in_stock')
    if in_stock is not None:
        if str(in_stock).lower() in ['true', '1', 'yes']:
            where_clauses.append("stock_quantity > 0")
    
    # Build WHERE clause
    if where_clauses:
        base_query += " WHERE " + " AND ".join(where_clauses)
    
    # Sorting
    sort_by = params.get('sort_by', 'created_at')
    sort_direction = params.get('sort_direction', 'DESC').upper()
    
    if sort_by in ALLOWED_SORT_FIELDS and sort_direction in ALLOWED_SORT_DIRECTIONS:
        base_query += f" ORDER BY {sort_by} {sort_direction}"
    else:
        base_query += " ORDER BY created_at DESC"
    
    # Pagination
    limit = validate_integer_input(params.get('limit', DEFAULT_LIMIT), min_val=1, max_val=MAX_LIMIT)
    if limit is None:
        limit = DEFAULT_LIMIT
    
    offset = validate_integer_input(params.get('offset', 0), min_val=0)
    if offset is None:
        offset = 0
    
    base_query += " LIMIT %s OFFSET %s"
    query_params.extend([limit, offset])
    
    return base_query, query_params


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """Main Lambda handler function"""
    
    try:
        # Extract query parameters from API Gateway event
        params = {}
        
        if 'queryStringParameters' in event and event['queryStringParameters']:
            params = event['queryStringParameters']
        elif 'body' in event and event['body']:
            try:
                params = json.loads(event['body'])
            except json.JSONDecodeError:
                return {
                    'statusCode': 400,
                    'headers': {
                        'Content-Type': 'application/json',
                        'Access-Control-Allow-Origin': '*'
                    },
                    'body': json.dumps({'error': 'Invalid JSON in request body'})
                }
        
        # Build secure parameterized query
        query, query_params = build_search_query(params)
        
        # Execute query with connection pooling
        connection = get_db_connection()
        
        try:
            with connection.cursor() as cursor:
                cursor.execute(query, query_params)
                results = cursor.fetchall()
                
                # Get total count for pagination
                count_query = "SELECT COUNT(*) as total FROM products"
                where_clause_start = query.find("WHERE")
                order_clause_start = query.find("ORDER BY")
                
                if where_clause_start != -1:
                    if order_clause_start != -1:
                        count_query += " " + query[where_clause_start:order_clause_start]
                    else:
                        limit_clause_start = query.find("LIMIT")
                        count_query += " " + query[where_clause_start:limit_clause_start]
                    
                    count_params = query_params[:-2]  # Exclude LIMIT and OFFSET
                    cursor.execute(count_query, count_params)
                else:
                    cursor.execute(count_query)
                
                total_count = cursor.fetchone()['total']
            
            return {
                'statusCode': 200,
                'headers': {
                    'Content-Type': 'application/json',
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({
                    'products': results,
                    'total': total_count,
                    'limit': query_params[-2],
                    'offset': query_params[-1]
                }, default=str)
            }
        
        finally:
            connection.close()
    
    except pymysql.MySQLError as e:
        # Log error without exposing sensitive details
        print(f"Database error occurred: {type(e).__name__}")
        
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': 'Database operation failed'})
        }
    
    except Exception as e:
        # Log error without exposing sensitive details
        print(f"Unexpected error occurred: {type(e).__name__}")
        
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': 'Internal server error'})
        }